/*
 * Kyiv badge: top-left counterpart to the logo. Stage-relative px so the
 * badge scales uniformly with `transform: scale()` from Slide.tsx. Matches
 * the visual weight of the DOU logo block to the right (84px tall band).
 * The title slide suppresses this via `showCityBadge={false}` and renders
 * its own calibrated `.title-hero__tag` inside the title block instead.
 */
.slide-chrome__city-badge {
  position: absolute;
  top: 27px;
  left: 55px;
  height: 84px;
  display: inline-flex;
  align-items: center;
  padding: 0 28px;
  background: var(--dou-near-black);
  color: var(--dou-white);
  font-family: var(--font-sans);
  font-weight: 600;
  font-size: 34px;
  line-height: 1;
  letter-spacing: 0;
  white-space: nowrap;
}

.slide-chrome__logo-image {
  position: absolute;
  top: -19px;
  left: -46px;
  width: 440px;

