 */
/*
 * Bio slide — two-column body layout inside the 1920×1080 stage:
 * left column is the "$ whoami" header + subtitle + bullet reveals,
 * right column is the speaker badges photo. Uses body-slide chrome
 * (randomised sonar + Kyiv badge + logo) from SlideChrome/SonarPattern.
 */
.bio-body {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  height: 100%;
  gap: 80px;
  text-align: left;
}

.bio-body__text {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.slide--body h2.bio-body__title {
  margin: 0;
  padding: 0;
  color: var(--dou-mint);
  font-family: var(--font-sans);
  font-size: 120px;
  font-weight: 700;
  line-height: 1;
  letter-spacing: -0.02em;
  text-align: left;
  text-transform: none;
}

.bio-body__title .text-dim {
  color: var(--dou-white-muted);
}

.slide--body p.bio-body__subtitle {
  margin: 0;
  color: var(--dou-magenta);
  font-family: var(--font-sans);
  font-size: 40px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  line-height: 1.15;
}

.bio-body__items {
  display: flex;
  flex-direction: column;
  gap: 14px;
  font-size: 38px;
  color: var(--dou-white);
}

.bio-body__item {
  display: grid;
  grid-template-columns: 48px 1fr;
  align-items: baseline;
  gap: 10px;
  line-height: 1.25;
}

.bio-body__item-prefix {
  font-weight: 700;
  font-size: 38px;
  letter-spacing: -0.02em;
}

.bio-body__item-label {
  color: var(--dou-white);
  font-weight: 400;
}

.bio-body__image {
  flex: 0 0 560px;
  height: 760px;
  border-radius: var(--input-border-radius);
  border: 2px solid var(--terminal-border);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
  overflow: hidden;
}

.bio-body__image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* === IMAGE SLIDE === */
/* For slides that display a single image filling available space */
.image-slide {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: calc(var(--vh-full) - 220px);
  max-height: calc(var(--vh-full) - 220px);
  overflow: hidden;
  padding: 0 var(--space-lg);
}

.image-slide img {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
  border-radius: var(--input-border-radius);
  border: 1px solid var(--terminal-border);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
}

@media (max-width: 768px) {

