/* Headings */
.slide h1 {
  font-size: var(--font-size-h1);
  font-weight: 600;
  color: var(--dou-magenta);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--letter-spacing-tight);
  line-height: var(--line-height-tight);
  font-family: var(--font-sans);
}

.slide h1.hero {
  font-size: var(--font-size-hero);
}

.slide h2 {
  font-size: var(--font-size-h2);
  font-weight: 600;
  color: var(--dou-mint);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--letter-spacing-tight);
  line-height: var(--line-height-tight);
  font-family: var(--font-sans);
}

.slide h3 {
  font-size: var(--font-size-h3);
  font-weight: 600;
  color: var(--dou-white);
  margin-bottom: var(--space-md);
  line-height: var(--line-height-tight);
  font-family: var(--font-sans);
}

/* Paragraphs */
.slide p {
  font-size: var(--slide-text-normal);
  line-height: var(--slide-line-height-normal);
  margin-bottom: var(--space-md);
  color: var(--dou-white-dim);
  font-family: var(--font-sans);
}

.slide p strong,
.slide p b {
  color: var(--dou-white);
  font-weight: 700;
}

.slide p em {
  color: var(--dou-magenta);
  font-style: normal;
  font-weight: 600;
}

/* Lists */
.slide ul,
.slide ol {
  list-style: none;
  text-align: left;
  display: inline-block;
  margin: var(--space-lg) 0;
}

.slide li {
  font-size: var(--slide-text-normal);
  margin-bottom: var(--space-md);
  padding-left: var(--space-xl);
  position: relative;
  line-height: var(--slide-line-height-normal);
  color: var(--dou-white);
  font-family: var(--font-sans);
}

.slide li::before {
  content: '•';
  position: absolute;
  left: 0;
  color: var(--dou-magenta);
  font-weight: 700;
  font-size: 1.4em;
  line-height: 1;
  top: 0.05em;
}

.slide ol {
  counter-reset: slide-counter;
}

.slide ol li::before {
  counter-increment: slide-counter;
  content: counter(slide-counter, decimal-leading-zero);
  color: var(--dou-magenta);
  font-weight: 600;
  font-size: 1em;
  font-variant-numeric: tabular-nums;
}

/* Inline code */
.slide code {
  background: var(--dou-bg-solid);
  padding: var(--space-xs) var(--space-sm);
  border-radius: var(--dou-radius-card);
  color: var(--dou-magenta);
  font-family: var(--font-mono);
  font-size: 0.9em;
  border: 1px solid var(--dou-magenta);
}

/* Links */
.slide a {
  color: var(--dou-mint);
  text-decoration: none;
  border-bottom: 1px solid var(--dou-mint);
  transition: all var(--transition-fast);
}

.slide a:hover {
  color: var(--dou-white);
  border-bottom-color: var(--dou-white);
}

/* Blockquotes */
.slide blockquote {
  border-left: 4px solid var(--dou-magenta);
  padding-left: var(--space-lg);
  margin: var(--space-lg) 0;
  font-style: normal;
  color: var(--dou-white-dim);
  font-family: var(--font-sans);
}

