:root {
  /* === DYNAMIC VIEWPORT HEIGHT === */
  --vh-full: 100vh;
  --vh-full: 100dvh; /* cascade override for supporting browsers */

  /* === LEGACY TERMINAL TOKEN ALIASES ===
     Class and variable names from the original terminal theme are preserved
     and remapped to DOU palette values so existing slide CSS keeps working
     without a 1500-line rewrite. When authoring new CSS, prefer --dou-*. */

  /* Backgrounds — all collapsed to the DOU dark surfaces */
  --terminal-bg: #0d021b;
  --terminal-bg-secondary: #0f0820;
  --terminal-bg-input: #0f0820;
  --terminal-bg-elevated: rgba(255, 255, 255, 0.04);

  /* Foreground text — DOU whites */
  --terminal-white: #ffffff;
  --terminal-white-dim: rgba(255, 255, 255, 0.78);
  --terminal-white-muted: rgba(255, 255, 255, 0.56);

  /* Accent roles — remapped: orange→magenta, green→mint, blue→violet */
  --terminal-orange: #ff16b1;
  --terminal-orange-dim: #c11288;
  --terminal-orange-glow: transparent;
  --terminal-orange-bright: #ff4ec3;

  --terminal-green: #02feb9;
  --terminal-green-dim: #6edab0;
  --terminal-green-glow: transparent;
  --terminal-green-bright: #02feb9;

  --terminal-blue: #7626ff;
  --terminal-blue-glow: transparent;
  --terminal-purple: #8d88fa;
  --terminal-purple-glow: transparent;
  --terminal-red: #ff6bd0;
  --terminal-red-glow: transparent;
  --terminal-cyan: #02d6fe;
  --terminal-cyan-glow: transparent;
  --terminal-yellow: #ffd166;

  /* Borders */
  --terminal-border: rgba(255, 255, 255, 0.12);
  --terminal-border-bright: rgba(255, 255, 255, 0.24);
  --terminal-border-focus: var(--terminal-orange);

  /* === TYPOGRAPHY === */
  --font-mono: 'JetBrains Mono', 'Fira Code', 'SF Mono', 'Cascadia Code', monospace;
  --font-sans: 'IBM Plex Sans', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif;

  /* === CANONICAL SLIDE TYPOGRAPHY ===
     Edit the three values below to retune every body slide in the deck.
     These are *the* knobs for making text bigger/smaller from a single
     place. Values are sized aggressively for back-row readability in a
     400+ seat hall. */
  --slide-text-h2: 4.5rem;       /* headings (was 3.5rem before convergence) */
  --slide-text-body: 2rem;       /* body text (was 1.35rem before) */
  --slide-text-code: 1.25rem;    /* code blocks */

  /* Backwards-compat aliases so older references keep working. Once every
     call site reads --slide-text-* directly, these can be removed. */
  --font-size-h2: var(--slide-text-h2);
  --slide-text-normal: var(--slide-text-body);
  --font-size-code: var(--slide-text-code);

  /* Secondary sizes — rarely on the tuning hot path */
  --font-size-hero: 6rem;
  --font-size-h1: 5rem;
  --font-size-h3: 2.5rem;
  --font-size-body: 1.75rem;
  --font-size-input: 1.125rem;
  --font-size-small: 0.875rem;

  --line-height-tight: 1.2;
  --line-height-normal: 1.6;
  --line-height-relaxed: 1.8;

  --letter-spacing-tight: -0.02em;
  --letter-spacing-normal: 0;
  --letter-spacing-wide: 0.05em;

  --slide-line-height-normal: 1.55;

  /* Section headers use same text size as body */
  --slide-section-header: var(--slide-text-body);

  /* Inline code */
  --slide-code-relative: 0.95em;

  /* === SPACING === */
  --space-xs: 0.25rem;
  --space-sm: 0.5rem;
  --space-md: 1rem;
  --space-lg: 2rem;
  --space-xl: 3rem;
  --space-2xl: 4rem;
  --space-3xl: 6rem;

  /* === INPUT STYLING === */
  --input-height: 3.5rem;
  --input-border-radius: 0.5rem;
  --input-padding-x: 1.25rem;

  /* === EFFECTS === */
  --transition-instant: 50ms ease;
  --transition-fast: 150ms ease;
  --transition-normal: 300ms ease-out;
  --transition-slow: 500ms ease-out;

  /* Glow effects — zeroed for DOU (no phosphor text-shadow) */
  --glow-orange: none;
  --glow-green: none;
  --glow-text-orange: none;
  --glow-text-green: none;

  /* CRT effects — zeroed */
  --scanline-opacity: 0;
  --noise-opacity: 0;
  --flicker-intensity: 0;

  /* === DOU DAYS 2026 DESIGN TOKENS === */

  /* Neutral / structure */
  --dou-white: #ffffff;
  --dou-deep-purple: #270950;
  --dou-near-black: #0d021b;
  --dou-navy: #002a42;

  /* Brand accents */
  --dou-magenta: #ff16b1;
  --dou-magenta-bright: #ff4ec3;
  --dou-mint: #02feb9;
  --dou-mint-dim: #6edab0;
  --dou-violet: #7626ff;
  --dou-violet-light: #8d88fa;
  --dou-teal: #0097a7;
  --dou-cyan: #02d6fe;

  /* Tonal utility (dim white for secondary body text on dark bg) */
  --dou-white-dim: rgba(255, 255, 255, 0.78);
  --dou-white-muted: rgba(255, 255, 255, 0.56);

  /* Backgrounds */
  --dou-bg-solid: #0f0820;
  --dou-bg-gradient: linear-gradient(135deg, #270950 0%, #0d021b 100%);

  /* Number-badge gradient (agenda pill) */
  --dou-gradient-badge: linear-gradient(180deg, #e252b8 0%, #b05cd1 100%);

  /* Radii */
  --dou-radius-pill: 9999px;
  --dou-radius-card: 4px;
}

/* Phone-size typography */
@media (max-width: 480px) {
  :root {
    --font-size-hero: 2rem;
    --font-size-h1: 1.6rem;
    --font-size-h2: 1.25rem;
    --font-size-h3: 1.1rem;
    --font-size-body: 0.9rem;
    --font-size-code: 0.8rem;
    --input-height: 2.75rem;
  }
}

