file.content:
.slide-item__prefix {
  color: var(--terminal-orange);
  font-weight: bold;
  text-shadow: 0 0 10px var(--terminal-orange-glow);
}

/* Slide Links */
.slide-link {
  color: var(--terminal-blue);
  text-decoration: none;
  border-bottom: 1px dashed var(--terminal-blue);
  transition: all var(--transition-fast);
  text-shadow: 0 0 8px var(--terminal-blue-glow);
}

.slide-link:hover {
  color: var(--terminal-cyan);
  border-bottom-color: var(--terminal-cyan);
  text-shadow: 0 0 12px var(--terminal-cyan-glow);
}

/* Text Emphasis */
.text-emphasis {
  font-weight: 600;
  font-style: normal;
}

.text-emphasis--orange {
  color: var(--terminal-orange);
  text-shadow: 0 0 6px var(--terminal-orange-glow);
}

.text-emphasis--green {
  color: var(--terminal-green);
  text-shadow: 0 0 6px var(--terminal-green-glow);
}

.text-quote {
  color: var(--terminal-orange);
  font-style: italic;
  text-shadow: 0 0 6px var(--terminal-orange-glow);
}

/* Slide Item Animation */
@keyframes slideItemFadeIn {
  from {
    opacity: 0;
    transform: translateX(-12px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideItemReveal {
  from {
    opacity: 0;
    transform: translateX(-32px);
  }
  60% {
    opacity: 1;
    transform: translateX(4px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

/* === RESPONSIVE === */
@media (max-width: 1024px) {
  :root {
    --font-size-hero: 3.5rem;
    --font-size-h1: 2.75rem;
    --font-size-h2: 2rem;
    --font-size-h3: 1.5rem;
    --font-size-body: 1.25rem;
  }

  .slide-container {
    padding: var(--space-xl) var(--space-lg);
  }
}

@media (max-width: 640px) {
  :root {
    --font-size-hero: 2.5rem;
    --font-size-h1: 2rem;
    --font-size-h2: 1.5rem;
    --font-size-h3: 1.25rem;
    --font-size-body: 1rem;
    --font-size-code: 0.875rem;
  }

  .slide-container {
    padding: var(--space-lg) var(--space-md);
  }

  .input-bar {
    padding: var(--space-sm) var(--space-md);
  }

}

/* Bio slide is now a hero slide; see `.bio-hero` below. */

/* === HERO STAGE (title slide) === */
/*
 * Hero slides render inside a fixed 1920x1080 stage that is uniformly
 * scaled by transform: scale(...) to fit the available viewport. This lets
 * us position template elements at exact template pixel coordinates and
 * still match the design on any window size.
 */

.slide-container--hero {
  padding: 0;
}

.stage-viewport {
  position: absolute;
  inset: 0;
  overflow: hidden;
  background: var(--dou-bg-gradient);
}

.stage {
  position: absolute;
  top: 50%;
  left: 50%;
  transform-origin: center center;
  /* width / height / transform set inline from Slide.tsx */
}

.slide--hero {
  position: absolute;
  inset: 0;
  max-width: none;
  max-height: none;
  width: 1920px;
  height: 1080px;
  padding: 0;
  margin: 0;
  overflow: hidden;
  animation: none;
  text-align: left;
  z-index: 2;
  background: transparent;
}

/*
 * Body slide inside the 1920×1080 stage. Content gets padded away from the
 * chrome band at the top (logo + Kyiv badge zone, ~140px) and from stage
 * edges horizontally. The slide still uses the existing `.slide` flex
 * layout for vertical centering of its content.
 */
.slide--body {
  position: absolute;
  inset: 0;
  max-width: none;
  max-height: none;
  width: 1920px;
  height: 1080px;
  padding: 140px 120px 60px;
  margin: 0;
  overflow: hidden;
  animation: none;
  text-align: center;
  z-index: 2;
  background: transparent;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: stretch;
}

/* --- Sonar background (concentric rings PNG from template) --- */

.sonar-pattern {
  position: absolute;
  pointer-events: none;
  user-select: none;
  z-index: 0;
}

/*
 * Source PNG is 1774×1774 (square). We replicate the DOU template's exact
 * transform: srcRect crop `l=3.508% r=5.126% t=22.464% b=26.143%` keeps
 * the middle-ish 1621×911 slice (≈16:9), then stretches it to fill a 16:9
 * box. Scale factors (horizontal 1.184, vertical 1.186) are nearly equal,
 * so rings stay visually circular. We implement the crop by displaying the
 * FULL image scaled to ~109.43% × 194.81% of the container and offsetting
 * by the negated crop origin (−3.80% / −43.80%). Using percentages lets the
 * wrapper fluidly fill the viewport width independent of the scaled stage.
 * See `.claude/skills/pixel-perfect-translation/references/calibration-methodology.md`.
 */
.sonar-pattern--hero {
  top: 50%;
  left: 0;
  width: 100%;
  aspect-ratio: 16 / 9;
  transform: translateY(-50%);
  overflow: hidden;
}

.sonar-pattern__image {
  position: absolute;
  top: -43.796%;
  left: -3.802%;
  width: 109.427%;
  height: 194.815%;
  display: block;
}

/*
 * Body-slide sonar: one of three full-bleed patterns extracted from the DOU
 * template content slides. The image picker (bodySonarFor) in
 * src/components/SonarPattern.tsx chooses deterministically per slide.
 * Opacity is dropped so slide text stays legible; object-fit cover handles
 * the different source aspect ratios (2048×1955, 2048×1152, 2014×2048).
 */
.sonar-pattern--body {
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
  opacity: var(--sonar-body-opacity, 0.35);
}

.sonar-pattern--body .sonar-pattern__image {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* --- Chrome (DOU logo top-right) --- */

.slide-chrome {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 3;
}

.slide-chrome__tag {
  display: none; /* Tag moved into the title block on hero slide */
}

/*
 * Source logo is 2048×571. Template crops via
 * srcRect l=10.42% r=6.751% t=15.672% b=15.679% (trims letter whitespace),
 * then stretches the ~1696×392 crop to 364×84. We reproduce the crop via
 * an inner <img> sized to the scaled source (440×122) and offset by the
 * scaled crop origin (−46, −19), so no aspect distortion.
 */
.slide-chrome__logo {
  position: absolute;
  top: 27px;
  left: 1501px;
  right: auto;
  width: 364px;
  height: 84px;
  overflow: hidden;
}

